import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { useAuth } from "../../contexts/AuthContext";

interface DashboardStats {
  totalPlatos: number;
  mesasActivas: number;
  pedidosHoy: number;
  totalUsuarios: number;
  ventasHoy: number;
  mesasLibres: number;
}

const Dashboard: React.FC = () => {
  const { usuario } = useAuth();
  const [stats, setStats] = useState<DashboardStats>({
    totalPlatos: 0,
    mesasActivas: 0,
    pedidosHoy: 0,
    totalUsuarios: 0,
    ventasHoy: 0,
    mesasLibres: 0,
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simular carga de estadísticas
    const loadStats = async () => {
      setLoading(true);
      // Aquí irían las llamadas reales a la API
      await new Promise((resolve) => setTimeout(resolve, 1000));
      setStats({
        totalPlatos: 25,
        mesasActivas: 8,
        pedidosHoy: 12,
        totalUsuarios: 6,
        ventasHoy: 1250,
        mesasLibres: 4,
      });
      setLoading(false);
    };

    loadStats();
  }, []);

  const dashboardCards = [
    {
      title: "Gestión de Menú",
      description: "Administrar platos, precios y disponibilidad",
      icon: "🍽️",
      path: "/menu",
      gradient: "from-blue-500 to-blue-600",
      stats: `${stats.totalPlatos} platos`,
    },
    {
      title: "Gestión de Mesas",
      description: "Configurar mesas y estados",
      icon: "🪑",
      path: "/mesas",
      gradient: "from-green-500 to-green-600",
      stats: `${stats.mesasLibres} libres`,
    },
    {
      title: "Gestión de Pedidos",
      description: "Ver y administrar pedidos activos",
      icon: "📋",
      path: "/pedidos",
      gradient: "from-orange-500 to-orange-600",
      stats: `${stats.pedidosHoy} hoy`,
    },
    {
      title: "Gestión de Usuarios",
      description: "Administrar usuarios del sistema",
      icon: "👥",
      path: "/usuarios",
      gradient: "from-purple-500 to-purple-600",
      stats: `${stats.totalUsuarios} usuarios`,
    },
  ];

  const StatCard: React.FC<{
    title: string;
    value: number | string;
    icon: string;
    change?: string;
    gradient: string;
  }> = ({ title, value, icon, change, gradient }) => (
    <div className="bg-white rounded-xl shadow-lg p-6 border border-gray-100 hover:shadow-xl transition-all duration-300 transform hover:-translate-y-1">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm font-medium text-gray-600 mb-1">{title}</p>
          <div className="text-3xl font-bold text-gray-900 mb-2">
            {loading ? (
              <div className="h-8 bg-gray-200 rounded animate-pulse w-16"></div>
            ) : (
              value
            )}
          </div>
          {change && (
            <p className="text-sm text-green-600 font-medium">{change}</p>
          )}
        </div>
        <div
          className={`p-4 rounded-xl bg-gradient-to-r ${gradient} shadow-lg`}
        >
          <span className="text-2xl">{icon}</span>
        </div>
      </div>
    </div>
  );

  return (
    <div className="max-w-7xl mx-auto space-y-8">
      {/* Header */}
      <div className="bg-white rounded-xl shadow-lg p-8 border border-gray-100">
        <div className="flex flex-col lg:flex-row lg:items-center lg:justify-between">
          <div>
            <h1 className="text-4xl font-bold bg-gradient-to-r from-blue-600 to-purple-600 bg-clip-text text-transparent mb-2">
              Panel de Administración
            </h1>
            <p className="text-gray-600 text-lg">
              Bienvenido/a,{" "}
              <span className="font-semibold text-gray-800">
                {usuario?.username}
              </span>
              . Gestiona tu restaurante desde aquí.
            </p>
          </div>
          <div className="mt-4 lg:mt-0">
            <div className="bg-gradient-to-r from-blue-50 to-purple-50 rounded-lg p-4">
              <div className="text-sm text-gray-600">Fecha actual</div>
              <div className="text-lg font-semibold text-gray-800">
                {new Date().toLocaleDateString("es-ES", {
                  weekday: "long",
                  year: "numeric",
                  month: "long",
                  day: "numeric",
                })}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Estadísticas principales */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard
          title="Ventas de Hoy"
          value={loading ? "..." : `$${stats.ventasHoy.toLocaleString()}`}
          icon="💰"
          change="+12% vs ayer"
          gradient="from-green-500 to-emerald-600"
        />
        <StatCard
          title="Pedidos Activos"
          value={loading ? "..." : stats.pedidosHoy}
          icon="📋"
          change="+3 nuevos"
          gradient="from-blue-500 to-blue-600"
        />
        <StatCard
          title="Mesas Ocupadas"
          value={loading ? "..." : `${stats.mesasActivas}/12`}
          icon="🪑"
          gradient="from-orange-500 to-red-600"
        />
        <StatCard
          title="Usuarios Online"
          value={loading ? "..." : stats.totalUsuarios}
          icon="👥"
          gradient="from-purple-500 to-pink-600"
        />
      </div>

      {/* Acciones rápidas */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {dashboardCards.map((card, index) => (
          <Link
            key={card.path}
            to={card.path}
            className="group bg-white rounded-xl shadow-lg p-6 border border-gray-100 hover:shadow-2xl transition-all duration-300 transform hover:-translate-y-2"
          >
            <div className="flex items-start justify-between mb-4">
              <div
                className={`p-4 rounded-xl bg-gradient-to-r ${card.gradient} shadow-lg group-hover:scale-110 transition-transform duration-300`}
              >
                <span className="text-3xl">{card.icon}</span>
              </div>
              <div className="text-right">
                <div className="text-sm text-gray-500">Estado</div>
                <div className="font-semibold text-gray-700">{card.stats}</div>
              </div>
            </div>

            <h3 className="text-xl font-bold text-gray-900 mb-2 group-hover:text-blue-600 transition-colors">
              {card.title}
            </h3>
            <p className="text-gray-600 mb-4">{card.description}</p>

            <div className="flex items-center text-blue-600 font-medium group-hover:text-blue-700">
              <span>Gestionar</span>
              <svg
                className="w-5 h-5 ml-2 transform group-hover:translate-x-1 transition-transform"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M17 8l4 4m0 0l-4 4m4-4H3"
                />
              </svg>
            </div>
          </Link>
        ))}
      </div>

      {/* Actividad reciente */}
      <div className="bg-white rounded-xl shadow-lg border border-gray-100">
        <div className="p-6 border-b border-gray-200">
          <h3 className="text-xl font-bold text-gray-900 flex items-center">
            <span className="mr-2">📊</span>
            Actividad Reciente
          </h3>
        </div>
        <div className="p-6">
          <div className="space-y-4">
            {[
              {
                action: "Nueva mesa agregada",
                time: "Hace 5 min",
                icon: "🪑",
                color: "text-green-600",
              },
              {
                action: "Pedido #123 completado",
                time: "Hace 10 min",
                icon: "✅",
                color: "text-blue-600",
              },
              {
                action: "Usuario registrado",
                time: "Hace 15 min",
                icon: "👤",
                color: "text-purple-600",
              },
              {
                action: "Menú actualizado",
                time: "Hace 30 min",
                icon: "🍽️",
                color: "text-orange-600",
              },
            ].map((activity, index) => (
              <div
                key={index}
                className="flex items-center p-4 bg-gray-50 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <div className="flex-shrink-0 mr-4">
                  <span className="text-xl">{activity.icon}</span>
                </div>
                <div className="flex-1">
                  <p className="font-medium text-gray-900">{activity.action}</p>
                  <p className="text-sm text-gray-500">{activity.time}</p>
                </div>
                <div className={`text-sm font-medium ${activity.color}`}>
                  Completado
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
